#!/bin/bash
set -e
echo "Building ibelieve-backend..."

# Create directories
mkdir -p ".github/workflows"
mkdir -p "examples"
mkdir -p "public/ibelieve"
mkdir -p "scripts"
mkdir -p "sql"
mkdir -p "sql/migrations"
mkdir -p "src"
mkdir -p "src/app/admin"
mkdir -p "src/app/api/admin"
mkdir -p "src/app/api/cron"
mkdir -p "src/app/api/events"
mkdir -p "src/app/api/feed"
mkdir -p "src/app/api/insights"
mkdir -p "src/app/api/posts"
mkdir -p "src/app/api/posts/[id]"
mkdir -p "src/app/api/replies"
mkdir -p "src/app/api/replies/[id]"
mkdir -p "src/lib/ai"
mkdir -p "src/lib/cache"
mkdir -p "src/lib/metrics"
mkdir -p "src/lib/supabase"
mkdir -p "tests"

# Write files
echo "" | base64 -d > "next.config.ts"
echo "" | base64 -d > "README.md"
echo "" | base64 -d > "package.json"
echo "" | base64 -d > "vercel.json"
echo "" | base64 -d > ".env.example"
echo "" | base64 -d > ".github/workflows/ci.yml"
echo "" | base64 -d > "tests/api.test.ts"
echo "" | base64 -d > "tests/unit.test.ts"
echo "" | base64 -d > "scripts/seed.ts"
echo "" | base64 -d > "examples/frontend-integration.ts"
echo "" | base64 -d > "sql/schema.sql"
echo "" | base64 -d > "sql/migrations/001_realtime_and_search.sql"
echo "" | base64 -d > "public/ibelieve/ibelieve-bridge.css"
echo "" | base64 -d > "public/ibelieve/ibelieve-bridge.js"
echo "" | base64 -d > "src/middleware.ts"
echo "" | base64 -d > "src/lib/metrics/compute.ts"
echo "" | base64 -d > "src/lib/metrics/insights.ts"
echo "" | base64 -d > "src/lib/cache/index.ts"
echo "" | base64 -d > "src/lib/ai/analyze.ts"
echo "" | base64 -d > "src/lib/supabase/client.ts"
echo "" | base64 -d > "src/lib/supabase/realtime.ts"
echo "" | base64 -d > "src/app/admin/page.tsx"
echo "" | base64 -d > "src/app/api/events/route.ts"
echo "" | base64 -d > "src/app/api/cron/route.ts"
echo "" | base64 -d > "src/app/api/insights/route.ts"
echo "" | base64 -d > "src/app/api/replies/route.ts"
echo "" | base64 -d > "src/app/api/replies/[id]/route.ts"
echo "" | base64 -d > "src/app/api/posts/route.ts"
echo "" | base64 -d > "src/app/api/posts/[id]/route.ts"
echo "" | base64 -d > "src/app/api/admin/route.ts"
echo "" | base64 -d > "src/app/api/feed/route.ts"

echo "All files created."
git add .
git commit -m "init: iBelieve backend"
git push -u origin main
echo "Pushed to GitHub!"